#include <stdio.h>
#include <stdlib.h>

double** allocate_matrix(int rows, int cols) {
    double** matrix;
    size_t total_size;
    
    // Calculate total size needed for the matrix
    total_size = rows * cols * sizeof(double);
    
    // Allocate memory for the matrix
    matrix = (double**)malloc(total_size);
    
    if (matrix == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return NULL;
    }
    
    return matrix;
}